'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useRouter } from 'next/navigation';
import { rolesAPI, assessmentAPI } from '../lib/api';
import AssessmentCard from '../components/AssessmentCard';
import type { Role, Question, ProfileFormData, AnswerData } from '../types';
import { ArrowRight, ArrowLeft, Loader2 } from 'lucide-react';

type Step = 'role' | 'profile' | 'questions' | 'loading';

export default function AssessmentPage() {
    const router = useRouter();
    const [step, setStep] = useState<Step>('role');
    const [roles, setRoles] = useState<Role[]>([]);
    const [selectedRole, setSelectedRole] = useState<number | null>(null);
    const [profileData, setProfileData] = useState<Partial<ProfileFormData>>({});
    const [questions, setQuestions] = useState<Question[]>([]);
    const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
    const [answers, setAnswers] = useState<Record<number, number>>({});
    const [assessmentId, setAssessmentId] = useState<number | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Load roles on mount
    useEffect(() => {
        loadRoles();
    }, []);

    const loadRoles = async () => {
        try {
            const data = await rolesAPI.getAll();
            setRoles(data);
        } catch (err) {
            setError('Failed to load roles. Please refresh the page.');
        }
    };

    const handleRoleSelect = (roleId: number) => {
        setSelectedRole(roleId);
    };

    const handleProfileSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedRole) return;

        setLoading(true);
        setError(null);

        try {
            const fullProfileData: ProfileFormData = {
                role_id: selectedRole,
                years_of_experience: profileData.years_of_experience!,
                company_type: profileData.company_type!,
                current_salary: profileData.current_salary!,
                target_role: profileData.target_role!,
                location: profileData.location,
                tech_stack: profileData.tech_stack,
                current_level: profileData.current_level,
            };

            const assessment = await assessmentAPI.start(fullProfileData);
            setAssessmentId(assessment.assessment_id);

            const questionsData = await assessmentAPI.getQuestions(assessment.assessment_id);
            setQuestions(questionsData);
            setStep('questions');
        } catch (err) {
            setError('Failed to start assessment. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleAnswerSelect = (answer: number) => {
        if (!questions[currentQuestionIndex]) return;

        const questionId = questions[currentQuestionIndex].id;
        setAnswers((prev) => ({ ...prev, [questionId]: answer }));
    };

    const handleNext = () => {
        if (currentQuestionIndex < questions.length - 1) {
            setCurrentQuestionIndex((prev) => prev + 1);
        }
    };

    const handlePrevious = () => {
        if (currentQuestionIndex > 0) {
            setCurrentQuestionIndex((prev) => prev - 1);
        }
    };

    const handleSubmitAssessment = async () => {
        if (!assessmentId) return;

        setLoading(true);
        setStep('loading');

        try {
            await assessmentAPI.submitAnswers(assessmentId, answers);
            await assessmentAPI.complete(assessmentId);

            router.push(`/dashboard/${assessmentId}`);
        } catch (err) {
            setError('Failed to submit assessment. Please try again.');
            setLoading(false);
            setStep('questions');
        }
    };

    const currentQuestion = questions[currentQuestionIndex];
    const isQuestionAnswered = currentQuestion && answers[currentQuestion.id] !== undefined;
    const allQuestionsAnswered = questions.length > 0 && questions.every((q) => answers[q.id] !== undefined);

    return (
        <div className="p-8 md:p-12">
            <div className="max-w-4xl mx-auto">
                {error && (
                    <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600 text-sm font-medium">
                        {error}
                    </div>
                )}

                {/* Step Indicator */}
                <div className="flex items-center justify-between mb-12 px-4">
                    {[
                        { id: 'role', label: 'Role Selection' },
                        { id: 'profile', label: 'Profile Context' },
                        { id: 'questions', label: 'Skills Assessment' }
                    ].map((s, i) => {
                        const isPast = ['role', 'profile', 'questions', 'loading'].indexOf(step) > ['role', 'profile', 'questions'].indexOf(s.id as any);
                        const isCurrent = step === s.id;

                        return (
                            <div key={s.id} className="flex items-center gap-4">
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${isCurrent ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' :
                                    isPast ? 'bg-emerald-500 text-white' : 'bg-slate-200 text-slate-500'
                                    }`}>
                                    {isPast ? '✓' : i + 1}
                                </div>
                                <span className={`text-sm font-semibold hidden md:block ${isCurrent ? 'text-slate-900' : 'text-slate-400'}`}>
                                    {s.label}
                                </span>
                                {i < 2 && <div className="w-12 h-px bg-slate-200 hidden md:block ml-4" />}
                            </div>
                        );
                    })}
                </div>

                <AnimatePresence mode="wait">
                    {/* Step 1: Role Selection */}
                    {step === 'role' && (
                        <motion.div
                            key="role"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -10 }}
                            className="space-y-8"
                        >
                            <div className="text-center">
                                <h1 className="heading-2 mb-2">Select Your Path</h1>
                                <p className="text-secondary">Which role best describes your current career track?</p>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {roles.map((role) => (
                                    <button
                                        key={role.id}
                                        onClick={() => handleRoleSelect(role.id)}
                                        className={`group text-left p-6 rounded-xl border transition-all ${selectedRole === role.id
                                            ? 'bg-indigo-50 border-indigo-200 ring-2 ring-indigo-600/10'
                                            : 'bg-white border-slate-200 hover:border-slate-300'
                                            }`}
                                    >
                                        <h3 className={`font-bold mb-1 transition-colors ${selectedRole === role.id ? 'text-indigo-900' : 'text-slate-900'}`}>
                                            {role.name}
                                        </h3>
                                        <p className="text-xs text-slate-500 line-clamp-2">{role.description}</p>
                                    </button>
                                ))}
                            </div>

                            <div className="flex justify-center pt-8 border-t border-slate-200">
                                <button
                                    onClick={() => selectedRole && setStep('profile')}
                                    disabled={!selectedRole}
                                    className="btn btn-primary px-8 py-3 disabled:opacity-50"
                                >
                                    Continue to Profile
                                    <ArrowRight className="ml-2" size={18} />
                                </button>
                            </div>
                        </motion.div>
                    )}

                    {/* Step 2: Profile Input */}
                    {step === 'profile' && (
                        <motion.div
                            key="profile"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -10 }}
                            className="space-y-8"
                        >
                            <div className="text-center">
                                <h1 className="heading-2 mb-2">Career Context</h1>
                                <p className="text-secondary">Provide your professional details for accurate benchmarking.</p>
                            </div>

                            <form onSubmit={handleProfileSubmit} className="card p-8 bg-white shadow-sm border-slate-200 space-y-8">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div className="space-y-6">
                                        <div>
                                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Years of Experience</label>
                                            <input
                                                type="number" step="0.5" min="0" required className="input"
                                                value={profileData.years_of_experience || ''}
                                                onChange={(e) => setProfileData(p => ({ ...p, years_of_experience: parseFloat(e.target.value) }))}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Company Type</label>
                                            <select
                                                required className="input"
                                                value={profileData.company_type || ''}
                                                onChange={(e) => setProfileData(p => ({ ...p, company_type: e.target.value as any }))}
                                            >
                                                <option value="">Select type...</option>
                                                <option value="Product">Product Company</option>
                                                <option value="Startup">Startup</option>
                                                <option value="Service">Service Agency</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div className="space-y-6">
                                        <div>
                                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Current Annual Salary (USD)</label>
                                            <input
                                                type="number" min="0" required className="input" placeholder="e.g. 120000"
                                                value={profileData.current_salary || ''}
                                                onChange={(e) => setProfileData(p => ({ ...p, current_salary: parseInt(e.target.value) }))}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Target Seniority / Level</label>
                                            <input
                                                type="text" required placeholder="e.g. Senior, Staff" className="input"
                                                value={profileData.target_role || ''}
                                                onChange={(e) => setProfileData(p => ({ ...p, target_role: e.target.value }))}
                                            />
                                        </div>
                                    </div>
                                </div>

                                <div className="pt-6 border-t border-slate-100 grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div>
                                        <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Current Level (Optional)</label>
                                        <input
                                            type="text" placeholder="e.g. L4, SSE" className="input bg-slate-50/50"
                                            value={profileData.current_level || ''}
                                            onChange={(e) => setProfileData(p => ({ ...p, current_level: e.target.value }))}
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Location (Optional)</label>
                                        <input
                                            type="text" placeholder="e.g. Remote, SF, NYC" className="input bg-slate-50/50"
                                            value={profileData.location || ''}
                                            onChange={(e) => setProfileData(p => ({ ...p, location: e.target.value }))}
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Tech Stack (Optional)</label>
                                    <input
                                        type="text" placeholder="React, Node.js, AWS (comma separated)" className="input bg-slate-50/50"
                                        value={profileData.tech_stack?.join(', ') || ''}
                                        onChange={(e) => setProfileData(p => ({ ...p, tech_stack: e.target.value.split(',').map(s => s.trim()).filter(s => !!s) }))}
                                    />
                                </div>

                                <div className="flex gap-4 pt-6 border-t border-slate-200">
                                    <button type="button" onClick={() => setStep('role')} className="btn btn-secondary flex-1 px-8">
                                        <ArrowLeft className="mr-2" size={18} />
                                        Back
                                    </button>
                                    <button type="submit" disabled={loading} className="btn btn-primary flex-1 px-8">
                                        {loading ? <Loader2 className="animate-spin" size={18} /> : 'Proceed to Questions'}
                                        {!loading && <ArrowRight className="ml-2" size={18} />}
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    )}

                    {/* Step 3: Questions */}
                    {step === 'questions' && currentQuestion && (
                        <motion.div
                            key="questions"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="space-y-12"
                        >
                            <div className="flex items-center justify-between">
                                <h1 className="heading-3">Assessment in Progress</h1>
                                <div className="text-sm font-bold text-slate-500 bg-slate-100 px-3 py-1 rounded-full uppercase tracking-tighter">
                                    Q{currentQuestionIndex + 1} of {questions.length}
                                </div>
                            </div>

                            <AssessmentCard
                                question={currentQuestion.question_text}
                                questionNumber={currentQuestionIndex + 1}
                                totalQuestions={questions.length}
                                dimension={currentQuestion.dimension}
                                selectedAnswer={answers[currentQuestion.id] || null}
                                onAnswerSelect={handleAnswerSelect}
                            />

                            <div className="flex gap-4 max-w-2xl mx-auto">
                                <button
                                    onClick={handlePrevious}
                                    disabled={currentQuestionIndex === 0}
                                    className="btn btn-secondary px-8"
                                >
                                    <ArrowLeft className="mr-2" size={18} />
                                    Previous
                                </button>

                                {currentQuestionIndex < questions.length - 1 ? (
                                    <button
                                        onClick={handleNext}
                                        disabled={!isQuestionAnswered}
                                        className="btn btn-primary flex-1 px-8"
                                    >
                                        Next Question
                                        <ArrowRight className="ml-2" size={18} />
                                    </button>
                                ) : (
                                    <button
                                        onClick={handleSubmitAssessment}
                                        disabled={!allQuestionsAnswered || loading}
                                        className="btn btn-primary flex-1 px-8"
                                    >
                                        {loading ? <Loader2 className="animate-spin" size={18} /> : 'Calculate My Intelligence Report'}
                                    </button>
                                )}
                            </div>
                        </motion.div>
                    )}

                    {/* Loading State */}
                    {step === 'loading' && (
                        <motion.div
                            key="loading"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            className="text-center py-20 bg-white rounded-3xl shadow-sm border border-slate-200"
                        >
                            <Loader2 className="w-12 h-12 text-indigo-600 animate-spin mx-auto mb-6" />
                            <h2 className="heading-3 mb-2">Analyzing Responses</h2>
                            <p className="text-secondary">Synthesizing benchmark data and generating your growth roadmap...</p>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
}
